    14→    private String location;             // 开庭地点
    15→    private long smsId;                 // 关联的短信ID
    16→    private long calendarEventId;        // 关联的日历事件ID
    17→    private long createdAt;             // 创建时间
    18→    private long updatedAt;             // 更新时间
    19→
    20→    public CourtCase() {
