    55→    }
    56→
    57→    public String getCourtShortName() {
    58→        return courtShortName;
    59→    }
    60→
    61→    public void setCourtShortName(String courtShortName) {
    62→        this.courtShortName = courtShortName;
    63→        this.updatedAt = System.currentTimeMillis();
