     3→import java.util.List;
     4→
     5→/**
     6→ * 法院短信信息模型
     7→ * 包含短信内容、解析状态、关联的文档等
     8→ */
     9→public class CourtMessage {
    10→    private long id;
    11→    private String sender;               // 发送者号码
    12→    private String content;              // 短信内容
    13→    private long receiveTime;           // 接收时间
    14→    private boolean hasLink;             // 是否包含链接
    15→    private int parseStatus;             // 解析状态：0=待解析, 1=已解析, 2=解析失败
    16→    private String documentIds;          // 关联的文档ID列表，逗号分隔
    17→    private boolean hasSummons;          // 是否包含传票
    18→    private String courtName;            // 解析出的法院名称
    19→    private String partyName;            // 解析出的当事人名称
    20→    private String caseNo;               // 解析出的案号
    21→    private long hearingDate;            // 解析出的开庭时间
    22→    private long createdAt;
    23→
    24→    public CourtMessage() {
    25→        this.parseStatus = 0;
    26→        this.hasLink = false;
    27→        this.hasSummons = false;
    28→        this.createdAt = System.currentTimeMillis();
    29→    }
    30→
    31→    public CourtMessage(String sender, String content, long receiveTime) {
    32→        this();
    33→        this.sender = sender;
    34→        this.content = content;
    35→        this.receiveTime = receiveTime;
    36→    }
    37→
    38→    // Getters and Setters
    39→    public long getId() {
    40→        return id;
    41→    }
    42→
    43→    public void setId(long id) {
    44→        this.id = id;
    45→    }
    46→
    47→    public String getSender() {
    48→        return sender;
    49→    }
    50→
    51→    public void setSender(String sender) {
    52→        this.sender = sender;
    53→    }
    54→
    55→    public String getContent() {
    56→        return content;
    57→    }
    58→
    59→    public void setContent(String content) {
    60→        this.content = content;
    61→    }
    62→
    63→    public long getReceiveTime() {
    64→        return receiveTime;
    65→    }
    66→
    67→    public void setReceiveTime(long receiveTime) {
    68→        this.receiveTime = receiveTime;
    69→    }
    70→
    71→    public boolean isHasLink() {
    72→        return hasLink;
    73→    }
    74→
    75→    public void setHasLink(boolean hasLink) {
    76→        this.hasLink = hasLink;
    77→    }
    78→
    79→    public int getParseStatus() {
    80→        return parseStatus;
    81→    }
    82→
    83→    public void setParseStatus(int parseStatus) {
    84→        this.parseStatus = parseStatus;
    85→    }
    86→
    87→    public String getDocumentIds() {
    88→        return documentIds;
    89→    }
    90→
    91→    public void setDocumentIds(String documentIds) {
    92→        this.documentIds = documentIds;
    93→    }
    94→
    95→    public boolean isHasSummons() {
    96→        return hasSummons;
    97→    }
    98→
    99→    public void setHasSummons(boolean hasSummons) {
   100→        this.hasSummons = hasSummons;
   101→    }
   102→
   103→    public String getCourtName() {
   104→        return courtName;
   105→    }
   106→
   107→    public void setCourtName(String courtName) {
   108→        this.courtName = courtName;
   109→    }
   110→
   111→    public String getPartyName() {
   112→        return partyName;
   113→    }
   114→
   115→    public void setPartyName(String partyName) {
   116→        this.partyName = partyName;
   117→    }
   118→
   119→    public String getCaseNo() {
   120→        return caseNo;
   121→    }
   122→
   123→    public void setCaseNo(String caseNo) {
   124→        this.caseNo = caseNo;
   125→    }
   126→
   127→    public long getHearingDate() {
   128→        return hearingDate;
   129→    }
   130→
   131→    public void setHearingDate(long hearingDate) {
   132→        this.hearingDate = hearingDate;
   133→    }
   134→
   135→    public long getCreatedAt() {
   136→        return createdAt;
   137→    }
   138→
   139→    public void setCreatedAt(long createdAt) {
   140→        this.createdAt = createdAt;
   141→    }
   142→
   143→    /**
   144→     * 添加文档ID
   145→     */
   146→    public void addDocumentId(long docId) {
   147→        if (documentIds == null || documentIds.isEmpty()) {
   148→            documentIds = String.valueOf(docId);
   149→        } else {
   150→            documentIds += "," + docId;
   151→        }
   152→    }
   153→
   154→    /**
   155→     * 获取文档ID列表
   156→     */
   157→    public List<Long> getDocumentIdList() {
   158→        if (documentIds == null || documentIds.isEmpty()) {
   159→            return java.util.Collections.emptyList();
   160→        }
   161→        String[] parts = documentIds.split(",");
   162→        List<Long> ids = new java.util.ArrayList<>();
   163→        for (String part : parts) {
   164→            try {
   165→                ids.add(Long.parseLong(part.trim()));
   166→            } catch (NumberFormatException e) {
   167→                // 忽略无效的ID
   168→            }
   169→        }
   170→        return ids;
   171→    }
   172→
   173→    /**
   174→     * 生成去重键
   175→     * 用于判断短信是否重复（基于短信内容和接收时间）
   176→     */
   177→    public String getDedupKey() {
   178→        // 使用短信内容的哈希和接收时间生成去重键
   179→        return content + "_" + (receiveTime / 5000); // 5秒内的相同短信视为重复
   180→    }
   181→
   182→    @Override
   183→    public boolean equals(Object o) {
   184→        if (this == o) return true;
   185→        if (o == null || getClass() != o.getClass()) return false;
   186→        CourtMessage that = (CourtMessage) o;
   187→        return content != null && content.equals(that.content) &&
   188→                Math.abs(receiveTime - that.receiveTime) < 5000;
   189→    }
   190→
   191→    @Override
   192→    public int hashCode() {
   193→        int result = content != null ? content.hashCode() : 0;
   194→        result = 31 * result + (int) (receiveTime / 5000);
   195→        return result;
   196→    }
   197→}
   198→

