package com.courassistant.java.utils;

import java.text.ParseException;
import java.text.SimpleDateFormat;
import java.util.Calendar;
import java.util.Date;
import java.util.Locale;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * 日期解析工具类
 * 支持解析各种中文日期格式，如 "2024年3月15日上午9:30"
 */
public class DateUtils {

    private static final String[] CHINESE_NUMBERS = {"零", "一", "二", "三", "四", "五", "六", "七", "八", "九", "十"};
    private static final String[] CHINESE_MONTHS = {"一", "二", "三", "四", "五", "六", "七", "八", "九", "十", "十一", "十二"};

    /**
     * 解析中文日期字符串
     * 支持多种格式：
     * - 2024年3月15日上午9:30
     * - 2024年03月15日 09:30
     * - 2024-03-15 09:30:00
     * - 2024/03/15 09:30
     * @param dateStr 日期字符串
     * @return 时间戳（毫秒），解析失败返回-1
     */
    public static long parseChineseDate(String dateStr) {
        if (dateStr == null || dateStr.isEmpty()) {
            return -1;
        }

        // 移除所有空格
        dateStr = dateStr.replaceAll("\\s+", "");

        // 尝试各种日期格式
        Long timestamp = tryParseFormats(dateStr);
        if (timestamp != null) {
            return timestamp;
        }

        // 尝试正则匹配中文日期格式
        timestamp = tryParseChineseFormat(dateStr);
        if (timestamp != null) {
            return timestamp;
        }

        return -1;
    }

    /**
     * 尝试多种标准日期格式
     */
    private static Long tryParseFormats(String dateStr) {
        String[] formats = {
            "yyyy年MM月dd日HH:mm",
            "yyyy年MM月dd日HH:mm:ss",
            "yyyy年MM月dd日HH时mm分",
            "yyyy-MM-dd HH:mm:ss",
            "yyyy-MM-dd HH:mm",
            "yyyy/MM/dd HH:mm:ss",
            "yyyy/MM/dd HH:mm",
            "yyyy.MM.dd HH:mm:ss",
            "yyyy.MM.dd HH:mm",
            "yyyy-MM-dd",
            "yyyy/MM/dd",
            "yyyy.MM.dd"
        };

        for (String format : formats) {
            try {
                SimpleDateFormat sdf = new SimpleDateFormat(format, Locale.CHINA);
                Date date = sdf.parse(dateStr);
                if (date != null) {
                    return date.getTime();
                }
            } catch (ParseException e) {
                // 继续尝试下一个格式
            }
        }

        return null;
    }

    /**
     * 尝试解析中文日期格式（如：2024年3月15日上午9:30）
     */
    private static Long tryParseChineseFormat(String dateStr) {
        // 匹配 2024年3月15日[上午|下午|中午|凌晨]9:30
        Pattern pattern = Pattern.compile("(\\d{4})年(\\d{1,2})月(\\d{1,2})日([上午下午中午凌晨])?(\\d{1,2}):?(\\d{2})?");
        Matcher matcher = pattern.matcher(dateStr);

        if (matcher.find()) {
            try {
                int year = Integer.parseInt(matcher.group(1));
                int month = Integer.parseInt(matcher.group(2));
                int day = Integer.parseInt(matcher.group(3));
                String period = matcher.group(4);
                String hourStr = matcher.group(5);
                String minuteStr = matcher.group(6);

                int hour = hourStr != null ? Integer.parseInt(hourStr) : 0;
                int minute = minuteStr != null ? Integer.parseInt(minuteStr) : 0;

                // 处理上午下午
                if (period != null) {
                    if ("下午".equals(period) || "中午".equals(period)) {
                        if (hour < 12) {
                            hour += 12;
                        }
                    } else if ("凌晨".equals(period)) {
                        // 凌晨保持原样，通常是0-5点
                    }
                    // "上午"保持原样
                }

                Calendar calendar = Calendar.getInstance();
                calendar.set(year, month - 1, day, hour, minute, 0);
                calendar.set(Calendar.MILLISECOND, 0);

                return calendar.getTimeInMillis();
            } catch (NumberFormatException e) {
                return null;
            }
        }

        // 匹配更宽松的格式
        return tryParseLooseFormat(dateStr);
    }

    /**
     * 尝试解析宽松的日期格式
     */
    private static Long tryParseLooseFormat(String dateStr) {
        // 匹配 2024年3月15日
        Pattern pattern = Pattern.compile("(\\d{4})年(\\d{1,2})月(\\d{1,2})日");
        Matcher matcher = pattern.matcher(dateStr);

        if (matcher.find()) {
            try {
                int year = Integer.parseInt(matcher.group(1));
                int month = Integer.parseInt(matcher.group(2));
                int day = Integer.parseInt(matcher.group(3));

                Calendar calendar = Calendar.getInstance();
                calendar.set(year, month - 1, day, 9, 0, 0);
                calendar.set(Calendar.MILLISECOND, 0);

                return calendar.getTimeInMillis();
            } catch (NumberFormatException e) {
                return null;
            }
        }

        return null;
    }

    /**
     * 将时间戳转换为格式化字符串
     * @param timestamp 时间戳（毫秒）
     * @param format 日期格式，如 "yyyy年MM月dd日 HH:mm"
     * @return 格式化后的字符串
     */
    public static String formatTimestamp(long timestamp, String format) {
        if (timestamp <= 0) {
            return "";
        }

        try {
            SimpleDateFormat sdf = new SimpleDateFormat(format, Locale.CHINA);
            return sdf.format(new Date(timestamp));
        } catch (Exception e) {
            return "";
        }
    }

    /**
     * 将时间戳转换为默认格式的字符串
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串，如 "2024年03月15日 09:30"
     */
    public static String formatTimestamp(long timestamp) {
        return formatTimestamp(timestamp, "yyyy年MM月dd日 HH:mm");
    }

    /**
     * 将时间戳转换为短格式字符串
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串，如 "2024-03-15"
     */
    public static String formatShortDate(long timestamp) {
        return formatTimestamp(timestamp, "yyyy-MM-dd");
    }

    /**
     * 将时间戳转换为长格式字符串
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串，如 "2024年03月15日 星期五 09:30:00"
     */
    public static String formatLongDate(long timestamp) {
        return formatTimestamp(timestamp, "yyyy年MM月dd日 E HH:mm:ss");
    }

    /**
     * 计算两个日期之间的天数差
     * @param timestamp1 第一个时间戳（毫秒）
     * @param timestamp2 第二个时间戳（毫秒）
     * @return 天数差（绝对值）
     */
    public static int daysBetween(long timestamp1, long timestamp2) {
        if (timestamp1 <= 0 || timestamp2 <= 0) {
            return -1;
        }

        long diff = Math.abs(timestamp1 - timestamp2);
        return (int) (diff / (1000 * 60 * 60 * 24));
    }

    /**
     * 计算两个日期之间的小时差
     * @param timestamp1 第一个时间戳（毫秒）
     * @param timestamp2 第二个时间戳（毫秒）
     * @return 小时数差（绝对值）
     */
    public static int hoursBetween(long timestamp1, long timestamp2) {
        if (timestamp1 <= 0 || timestamp2 <= 0) {
            return -1;
        }

        long diff = Math.abs(timestamp1 - timestamp2);
        return (int) (diff / (1000 * 60 * 60));
    }

    /**
     * 计算两个日期之间的分钟差
     * @param timestamp1 第一个时间戳（毫秒）
     * @param timestamp2 第二个时间戳（毫秒）
     * @return 分钟数差（绝对值）
     */
    public static int minutesBetween(long timestamp1, long timestamp2) {
        if (timestamp1 <= 0 || timestamp2 <= 0) {
            return -1;
        }

        long diff = Math.abs(timestamp1 - timestamp2);
        return (int) (diff / (1000 * 60));
    }

    /**
     * 判断日期是否在今天
     * @param timestamp 时间戳（毫秒）
     * @return true如果是今天
     */
    public static boolean isToday(long timestamp) {
        if (timestamp <= 0) {
            return false;
        }

        Calendar today = Calendar.getInstance();
        Calendar target = Calendar.getInstance();
        target.setTimeInMillis(timestamp);

        return today.get(Calendar.YEAR) == target.get(Calendar.YEAR) &&
                today.get(Calendar.MONTH) == target.get(Calendar.MONTH) &&
                today.get(Calendar.DAY_OF_MONTH) == target.get(Calendar.DAY_OF_MONTH);
    }

    /**
     * 判断日期是否在指定天数内
     * @param timestamp 时间戳（毫秒）
     * @param days 天数
     * @return true如果在指定天数内
     */
    public static boolean isWithinDays(long timestamp, int days) {
        if (timestamp <= 0) {
            return false;
        }

        long currentTime = System.currentTimeMillis();
        long diff = timestamp - currentTime;
        long daysInMillis = days * 24 * 60 * 60 * 1000L;

        return diff >= 0 && diff <= daysInMillis;
    }

    /**
     * 获取日期的中文星期
     * @param timestamp 时间戳（毫秒）
     * @return 中文星期，如 "星期五"
     */
    public static String getChineseWeekday(long timestamp) {
        if (timestamp <= 0) {
            return "";
        }

        Calendar calendar = Calendar.getInstance();
        calendar.setTimeInMillis(timestamp);

        int weekday = calendar.get(Calendar.DAY_OF_WEEK);
        String[] weekdays = {"星期日", "星期一", "星期二", "星期三", "星期四", "星期五", "星期六"};

        return weekdays[weekday - 1];
    }

    /**
     * 添加天数到日期
     * @param timestamp 原始时间戳（毫秒）
     * @param days 要添加的天数
     * @return 新的时间戳
     */
    public static long addDays(long timestamp, int days) {
        if (timestamp <= 0) {
            return -1;
        }

        Calendar calendar = Calendar.getInstance();
        calendar.setTimeInMillis(timestamp);
        calendar.add(Calendar.DAY_OF_MONTH, days);

        return calendar.getTimeInMillis();
    }

    /**
     * 添加小时到日期
     * @param timestamp 原始时间戳（毫秒）
     * @param hours 要添加的小时数
     * @return 新的时间戳
     */
    public static long addHours(long timestamp, int hours) {
        if (timestamp <= 0) {
            return -1;
        }

        Calendar calendar = Calendar.getInstance();
        calendar.setTimeInMillis(timestamp);
        calendar.add(Calendar.HOUR_OF_DAY, hours);

        return calendar.getTimeInMillis();
    }

    /**
     * 解析中文数字（如"一"、"二"、"十"等）
     * @param chineseNum 中文数字字符串
     * @return 阿拉伯数字，解析失败返回-1
     */
    public static int parseChineseNumber(String chineseNum) {
        if (chineseNum == null || chineseNum.isEmpty()) {
            return -1;
        }

        // 处理1-10的简单情况
        for (int i = 1; i <= 10; i++) {
            if (CHINESE_NUMBERS[i].equals(chineseNum)) {
                return i;
            }
        }

        // 处理11-19的情况（如"十一"、"十二"等）
        if (chineseNum.length() == 2 && chineseNum.startsWith("十")) {
            String second = chineseNum.substring(1);
            for (int i = 1; i <= 9; i++) {
                if (CHINESE_NUMBERS[i].equals(second)) {
                    return 10 + i;
                }
            }
            return 10; // "十"
        }

        // 处理月份（一月到十二月）
        for (int i = 0; i < CHINESE_MONTHS.length; i++) {
            if (CHINESE_MONTHS[i].equals(chineseNum)) {
                return i + 1;
            }
        }

        return -1;
    }

    /**
     * 获取当前时间的字符串表示
     * @return 当前时间字符串，如 "2024年03月15日 09:30:00"
     */
    public static String getCurrentTimeString() {
        return formatTimestamp(System.currentTimeMillis(), "yyyy年MM月dd日 HH:mm:ss");
    }

    /**
     * 获取今天的日期字符串
     * @return 今天日期字符串，如 "2024-03-15"
     */
    public static String getTodayString() {
        return formatShortDate(System.currentTimeMillis());
    }
}

