package com.courassistant.java.database;

import androidx.room.Entity;
import androidx.room.Index;
import androidx.room.PrimaryKey;

/**
 * 法院短信信息数据库实体
 */
@Entity(
    tableName = "court_messages",
    indices = {
        @Index(value = {"receiveTime"}),
        @Index(value = {"parseStatus"}),
        @Index(value = {"hasSummons"}),
        @Index(value = {"caseNo"})
    }
)
public class CourtMessageEntity {

    @PrimaryKey(autoGenerate = true)
    private long id;

    private String sender;               // 发送者号码
    private String content;              // 短信内容
    private long receiveTime;           // 接收时间
    private boolean hasLink;             // 是否包含链接
    private int parseStatus;             // 解析状态：0=待解析, 1=已解析, 2=解析失败
    private String documentIds;          // 关联的文档ID列表，逗号分隔
    private boolean hasSummons;          // 是否包含传票
    private String courtName;            // 解析出的法院名称
    private String partyName;            // 解析出的当事人名称
    private String caseNo;               // 解析出的案号
    private long hearingDate;            // 解析出的开庭时间
    private long createdAt;

    public CourtMessageEntity() {
        this.parseStatus = 0;
        this.hasLink = false;
        this.hasSummons = false;
        this.createdAt = System.currentTimeMillis();
        this.receiveTime = 0;
        this.hearingDate = 0;
    }

    public CourtMessageEntity(String sender, String content, long receiveTime) {
        this();
        this.sender = sender;
        this.content = content;
        this.receiveTime = receiveTime;
    }

    // Getters and Setters
    public long getId() {
        return id;
    }

    public void setId(long id) {
        this.id = id;
    }

    public String getSender() {
        return sender;
    }

    public void setSender(String sender) {
        this.sender = sender;
    }

    public String getContent() {
        return content;
    }

    public void setContent(String content) {
        this.content = content;
    }

    public long getReceiveTime() {
        return receiveTime;
    }

    public void setReceiveTime(long receiveTime) {
        this.receiveTime = receiveTime;
    }

    public boolean isHasLink() {
        return hasLink;
    }

    public void setHasLink(boolean hasLink) {
        this.hasLink = hasLink;
    }

    public int getParseStatus() {
        return parseStatus;
    }

    public void setParseStatus(int parseStatus) {
        this.parseStatus = parseStatus;
    }

    public String getDocumentIds() {
        return documentIds;
    }

    public void setDocumentIds(String documentIds) {
        this.documentIds = documentIds;
    }

    public boolean isHasSummons() {
        return hasSummons;
    }

    public void setHasSummons(boolean hasSummons) {
        this.hasSummons = hasSummons;
    }

    public String getCourtName() {
        return courtName;
    }

    public void setCourtName(String courtName) {
        this.courtName = courtName;
    }

    public String getPartyName() {
        return partyName;
    }

    public void setPartyName(String partyName) {
        this.partyName = partyName;
    }

    public String getCaseNo() {
        return caseNo;
    }

    public void setCaseNo(String caseNo) {
        this.caseNo = caseNo;
    }

    public long getHearingDate() {
        return hearingDate;
    }

    public void setHearingDate(long hearingDate) {
        this.hearingDate = hearingDate;
    }

    public long getCreatedAt() {
        return createdAt;
    }

    public void setCreatedAt(long createdAt) {
        this.createdAt = createdAt;
    }

    /**
     * 添加文档ID
     */
    public void addDocumentId(long docId) {
        if (documentIds == null || documentIds.isEmpty()) {
            documentIds = String.valueOf(docId);
        } else {
            documentIds += "," + docId;
        }
    }

    /**
     * 生成去重键
     * 用于判断短信是否重复（基于短信内容和接收时间）
     */
    public String getDedupKey() {
        return content + "_" + (receiveTime / 5000);
    }
}

package com.courassistant.java.database;

import androidx.room.Entity;
import androidx.room.Index;
import androidx.room.PrimaryKey;

/**
 * 法院文档信息数据库实体
 */
@Entity(
    tableName = "court_documents",
    indices = {
        @Index(value = {"caseId"}),
        @Index(value = {"isSummons"}),
        @Index(value = {"parseStatus"}),
        @Index(value = {"calendarSynced"})
    }
)
public class CourtDocumentEntity {

    public static final int PARSE_STATUS_PENDING = 0;       // 待解析
    public static final int PARSE_STATUS_PARSED = 1;         // 已解析
    public static final int PARSE_STATUS_FAILED = 2;          // 解析失败
    public static final int PARSE_STATUS_NOT_SUMMONS = 3;     // 非传票
    public static final int PARSE_STATUS_PENDING_WEBVIEW = 4; // 待WebView处理
    public static final int PARSE_STATUS_PROCESSING = 5;      // 处理中

    @PrimaryKey(autoGenerate = true)
    private long id;

    private long caseId;               // 关联的案件ID
    private String fileName;            // 文件名
    private String filePath;            // 文件路径
    private long fileSize;             // 文件大小（字节）
    private String fileType;            // 文件类型
    private String downloadUrl;         // 下载来源URL
    private boolean isSummons;         // 是否为传票
    private long downloadTime;         // 下载时间
    private int parseStatus;            // 解析状态
