package com.courassistant.java.database;

import androidx.room.Entity;
import androidx.room.Index;
import androidx.room.PrimaryKey;

/**
 * 日历同步记录数据库实体
 */
@Entity(
    tableName = "calendar_sync_record",
    indices = {
        @Index(value = {"sourceId", "sourceType"}),
        @Index(value = {"syncStatus"}),
        @Index(value = {"dedupKey"}, unique = true),
        @Index(value = {"eventId"}),
        @Index(value = {"startTime"})
    }
)
public class CalendarSyncRecordEntity {

    public static final int SYNC_STATUS_PENDING = 0;    // 待同步
    public static final int SYNC_STATUS_SYNCED = 1;     // 已同步
    public static final int SYNC_STATUS_FAILED = 2;      // 同步失败

    @PrimaryKey(autoGenerate = true)
    private long id;

    private long sourceId;              // 来源ID（案件ID或文档ID）
    private String sourceType;          // 来源类型："case" 或 "document"
    private long eventId;               // 日历事件ID
    private int syncStatus;             // 同步状态
    private String dedupKey;            // 去重键
    private long syncedAt;             // 同步时间
    private String calendarId;          // 日历账户ID
    private String title;               // 事件标题
    private long startTime;             // 开始时间
    private long endTime;               // 结束时间
    private String description;         // 事件描述
    private String location;             // 事件地点
    private long createdAt;

    public CalendarSyncRecordEntity() {
        this.syncStatus = SYNC_STATUS_PENDING;
        this.createdAt = System.currentTimeMillis();
        this.sourceId = 0;
        this.eventId = 0;
        this.startTime = 0;
        this.endTime = 0;
    }

    public CalendarSyncRecordEntity(long sourceId, String sourceType, String dedupKey) {
        this();
        this.sourceId = sourceId;
        this.sourceType = sourceType;
        this.dedupKey = dedupKey;
    }

    // Getters and Setters
    public long getId() {
        return id;
    }

    public void setId(long id) {
        this.id = id;
    }

    public long getSourceId() {
        return sourceId;
    }

    public void setSourceId(long sourceId) {
        this.sourceId = sourceId;
    }

    public String getSourceType() {
        return sourceType;
    }

    public void setType(String sourceType) {
        this.sourceType = sourceType;
    }

    public long getEventId() {
        return eventId;
    }

    public void setEventId(long eventId) {
        this.eventId = eventId;
        this.syncStatus = SYNC_STATUS_SYNCED;
        this.syncedAt = System.currentTimeMillis();
    }

    public int getSyncStatus() {
        return syncStatus;
    }

    public void setSyncStatus(int syncStatus) {
        this.syncStatus = syncStatus;
        if (syncStatus == SYNC_STATUS_SYNCED) {
            this.syncedAt = System.currentTimeMillis();
        }
    }

    public String getDedupKey() {
        return dedupKey;
    }

    public void setDedupKey(String dedupKey) {
        this.dedupKey = dedupKey;
    }

    public long getSyncedAt() {
        return syncedAt;
    }

    public void setSyncedAt(long syncedAt) {
        this.syncedAt = syncedAt;
    }

    public String getCalendarId() {
        return calendarId;
    }

    public void setCalendarId(String calendarId) {
        this.calendarId = calendarId;
    }

    public String getTitle() {
        return title;
    }

    public void setTitle(String title) {
        this.title = title;
    }

    public long getStartTime() {
        return startTime;
    }

    public void setStartTime(long startTime) {
        this.startTime = startTime;
    }

    public long getEndTime() {
        return endTime;
    }

    public void setEndTime(long endTime) {
        this.endTime = endTime;
    }

    public String getDescription() {
        return description;
    }

    public void setDescription(String description) {
        this.description = description;
    }

    public String getLocation() {
        return location;
    }

    public void setLocation(String location) {
        this.location = location;
    }

    public long getCreatedAt() {
        return createdAt;
    }

    public void setCreatedAt(long createdAt) {
        this.createdAt = createdAt;
    }

    /**
     * 检查是否已成功同步
     */
    public boolean isSynced() {
        return syncStatus == SYNC_STATUS_SYNCED && eventId > 0;
    }

    /**
     * 根据案件信息生成去重键
     */
    public static String buildDedupKey(String caseNo, long startTime) {
        return caseNo + "_" + startTime;
    }
}

package com.courassistant.java.database;

import androidx.room.Dao;
import androidx.room.Delete;
import androidx.room.Insert;
import androidx.room.OnConflictStrategy;
import androidx.room.Query;
import androidx.room.Update;

import java.util.List;

/**
 * 案件数据访问接口
 */
@Dao
public interface CourtCaseDao {

    /**
     * 插入新案件
     * 如果案号已存在则替换
     */
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    long insert(CourtCaseEntity courtCase);

    /**
     * 批量插入案件
     */
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    List<Long> insertAll(List<CourtCaseEntity> courtCases);

    /**
     * 更新案件信息
     */
    @Update
    int update(CourtCaseEntity courtCase);

    /**
     * 删除案件
     */
    @Delete
    int delete(CourtCaseEntity courtCase);

    /**
     * 根据ID查询案件
     */
    @Query("SELECT * FROM court_cases WHERE id = :id")
    CourtCaseEntity getById(long id);

    /**
     * 根据案号查询案件
     */
    @Query("SELECT * FROM court_cases WHERE caseNo = :caseNo LIMIT 1")
    CourtCaseEntity getByCaseNo(String caseNo);

    /**
     * 查询所有案件
     */
    @Query("SELECT * FROM court_cases ORDER BY hearingDate DESC")
    List<CourtCaseEntity> getAll();

    /**
     * 查询所有案件（按创建时间倒序）
     */
    @Query("SELECT * FROM court_cases ORDER BY createdAt DESC")
    List<CourtCaseEntity> getAllOrderByCreatedAt();

    /**
     * 根据开庭日期范围查询案件
     */
    @Query("SELECT * FROM court_cases WHERE hearingDate >= :startTime AND hearingDate <= :endTime ORDER BY hearingDate ASC")
    List<CourtCaseEntity> getByHearingDateRange(long startTime, long endTime);

    /**
     * 查询即将开庭的案件（从现在开始指定天数内）
     */
    @Query("SELECT * FROM court_cases WHERE hearingDate >= :currentTime AND hearingDate <= :endTime ORDER BY hearingDate ASC")
    List<CourtCaseEntity> getUpcomingCases(long currentTime, long endTime);

    /**
     * 根据短信ID查询关联的案件
     */
    @Query("SELECT * FROM court_cases WHERE smsId = :smsId LIMIT 1")
    CourtCaseEntity getBySmsId(long smsId);

    /**
     * 根据日历事件ID查询关联的案件
     */
    @Query("SELECT * FROM court_cases WHERE calendarEventId = :eventId LIMIT 1")
    CourtCaseEntity getByCalendarEventId(long eventId);

    /**
     * 根据法院简称查询案件
     */
    @Query("SELECT * FROM court_cases WHERE courtShortName = :courtName ORDER BY hearingDate DESC")
    List<CourtCaseEntity> getByCourtName(String courtName);

    /**
     * 根据当事人名称查询案件
     */
    @Query("SELECT * FROM court_cases WHERE partyName LIKE '%' || :partyName || '%' ORDER BY hearingDate DESC")
    List<CourtCaseEntity> getByPartyName(String partyName);

    /**
     * 搜索案件（支持案号、法院名称、当事人名称模糊查询）
     */
    @Query("SELECT * FROM court_cases WHERE caseNo LIKE '%' || :keyword || '%' " +
           "OR courtFullName LIKE '%' || :keyword || '%' " +
           "OR courtShortName LIKE '%' || :keyword || '%' " +
           "OR partyName LIKE '%' || :keyword || '%' " +
           "ORDER BY hearingDate DESC")
    List<CourtCaseEntity> search(String keyword);

    /**
     * 统计案件总数
     */
    @Query("SELECT COUNT(*) FROM court_cases")
    int getCount();

    /**
     * 统计指定时间段内的案件数量
     */
    @Query("SELECT COUNT(*) FROM court_cases WHERE hearingDate >= :startTime AND hearingDate <= :endTime")
    int getCountByDateRange(long startTime, long endTime);

    /**
     * 删除指定ID的案件
     */
    @Query("DELETE FROM court_cases WHERE id = :id")
    int deleteById(long id);

    /**
     * 删除所有案件
     */
    @Query("DELETE FROM court_cases")
    int deleteAll();

    /**
     * 更新案件的日历事件ID
     */
    @Query("UPDATE court_cases SET calendarEventId = :eventId, updatedAt = :updatedAt WHERE id = :id")
    int updateCalendarEventId(long id, long eventId, long updatedAt);

    /**
     * 查询未同步到日历的案件
     */
    @Query("SELECT * FROM court_cases WHERE calendarEventId = 0 OR calendarEventId IS NULL ORDER BY hearingDate ASC")
    List<CourtCaseEntity> getUnsyncedCases();

    /**
     * 查询已过期的案件（开庭时间早于指定时间）
     */
    @Query("SELECT * FROM court_cases WHERE hearingDate < :time ORDER BY hearingDate DESC")
    List<CourtCaseEntity> getPastCases(long time);

    /**
     * 查询最近更新的案件
     */
    @Query("SELECT * FROM court_cases ORDER BY updatedAt DESC LIMIT :limit")
    List<CourtCaseEntity> getRecentlyUpdated(int limit);
}

