package com.courassistant.java.database;

import androidx.room.Dao;
import androidx.room.Delete;
import androidx.room.Insert;
import androidx.room.OnConflictStrategy;
import androidx.room.Query;
import androidx.room.Update;

import java.util.List;

/**
 * 日历同步记录数据访问接口
 */
@Dao
public interface CalendarSyncDao {

    /**
     * 插入新的同步记录
     */
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    long insert(CalendarSyncRecordEntity record);

    /**
     * 批量插入同步记录
     */
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    List<Long> insertAll(List<CalendarSyncRecordEntity> records);

    /**
     * 更新同步记录
     */
    @Update
    int update(CalendarSyncRecordEntity record);

    /**
     * 删除同步记录
     */
    @Delete
    int delete(CalendarSyncRecordEntity record);

    /**
     * 根据ID查询同步记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE id = :id")
    CalendarSyncRecordEntity getById(long id);

    /**
     * 查询所有同步记录
     */
    @Query("SELECT * FROM calendar_sync_record ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> getAll();

    /**
     * 根据来源ID和类型查询同步记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE sourceId = :sourceId AND sourceType = :sourceType LIMIT 1")
    CalendarSyncRecordEntity getBySource(long sourceId, String sourceType);

    /**
     * 根据去重键查询同步记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE dedupKey = :dedupKey LIMIT 1")
    CalendarSyncRecordEntity getByDedupKey(String dedupKey);

    /**
     * 根据同步状态查询记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = :status ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> getBySyncStatus(int status);

    /**
     * 查询待同步的记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 0 ORDER BY createdAt ASC")
    List<CalendarSyncRecordEntity> getPendingRecords();

    /**
     * 查询已同步的记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 1 ORDER BY syncedAt DESC")
    List<CalendarSyncRecordEntity> getSyncedRecords();

    /**
     * 查询同步失败的记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 2 ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> getFailedRecords();

    /**
     * 根据日历事件ID查询同步记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE eventId = :eventId LIMIT 1")
    CalendarSyncRecordEntity getByEventId(long eventId);

    /**
     * 根据开始时间范围查询记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE startTime >= :startTime AND startTime <= :endTime ORDER BY startTime ASC")
    List<CalendarSyncRecordEntity> getByStartTimeRange(long startTime, long endTime);

    /**
     * 根据日历账户ID查询记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE calendarId = :calendarId ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> getByCalendarId(String calendarId);

    /**
     * 搜索同步记录（标题、描述、地点）
     */
    @Query("SELECT * FROM calendar_sync_record WHERE title LIKE '%' || :keyword || '%' " +
           "OR description LIKE '%' || :keyword || '%' " +
           "OR location LIKE '%' || :keyword || '%' " +
           "ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> search(String keyword);

    /**
     * 统计同步记录总数
     */
    @Query("SELECT COUNT(*) FROM calendar_sync_record")
    int getCount();

    /**
     * 统计指定状态的记录数量
     */
    @Query("SELECT COUNT(*) FROM calendar_sync_record WHERE syncStatus = :status")
    int getCountByStatus(int status);

    /**
     * 统计来源类型的记录数量
     */
    @Query("SELECT COUNT(*) FROM calendar_sync_record WHERE sourceType = :sourceType")
    int getCountBySourceType(String sourceType);

    /**
     * 删除指定ID的记录
     */
    @Query("DELETE FROM calendar_sync_record WHERE id = :id")
    int deleteById(long id);

    /**
     * 根据来源ID和类型删除记录
     */
    @Query("DELETE FROM calendar_sync_record WHERE sourceId = :sourceId AND sourceType = :sourceType")
    int deleteBySource(long sourceId, String sourceType);

    /**
     * 删除所有记录
     */
    @Query("DELETE FROM calendar_sync_record")
    int deleteAll();

    /**
     * 删除指定时间之前的记录
     */
    @Query("DELETE FROM calendar_sync_record WHERE createdAt < :time")
    int deleteOldRecords(long time);

    /**
     * 删除已同步且过期的记录（已同步且开始时间已过）
     */
    @Query("DELETE FROM calendar_sync_record WHERE syncStatus = 1 AND startTime < :time")
    int deleteOldSyncedRecords(long time);

    /**
     * 更新同步状态
     */
    @Query("UPDATE calendar_sync_record SET syncStatus = :status WHERE id = :id")
    int updateSyncStatus(long id, int status);

    /**
     * 批量更新同步状态
     */
    @Query("UPDATE calendar_sync_record SET syncStatus = :status WHERE id IN (:ids)")
    int updateSyncStatusBatch(List<Long> ids, int status);

    /**
     * 更新同步成功（设置事件ID和同步时间）
     */
    @Query("UPDATE calendar_sync_record SET eventId = :eventId, syncStatus = 1, syncedAt = :syncedAt WHERE id = :id")
    int updateSynced(long id, long eventId, long syncedAt);

    /**
     * 查询最近的同步记录
     */
    @Query("SELECT * FROM calendar_sync_record ORDER BY createdAt DESC LIMIT :limit")
    List<CalendarSyncRecordEntity> getRecentRecords(int limit);

    /**
     * 查询即将开始的日历事件（从现在开始指定天数内）
     */
    @Query("SELECT * FROM calendar_sync_record WHERE startTime >= :currentTime AND startTime <= :endTime AND syncStatus = 1 ORDER BY startTime ASC")
    List<CalendarSyncRecordEntity> getUpcomingEvents(long currentTime, long endTime);

    /**
     * 查询已过去的日历事件
     */
    @Query("SELECT * FROM calendar_sync_record WHERE startTime < :time AND syncStatus = 1 ORDER BY startTime DESC")
    List<CalendarSyncRecordEntity> getPastEvents(long time);

    /**
     * 根据案件案号查询相关同步记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE title LIKE '%' || :caseNo || '%' ORDER BY startTime DESC")
    List<CalendarSyncRecordEntity> getByCaseNo(String caseNo);

    /**
     * 检查是否存在重复的同步记录（基于去重键）
     */
    @Query("SELECT COUNT(*) FROM calendar_sync_record WHERE dedupKey = :dedupKey")
    int countByDedupKey(String dedupKey);

    /**
     * 查询需要重新同步的记录（同步失败或未同步的）
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus IN (0, 2) ORDER BY createdAt ASC")
    List<CalendarSyncRecordEntity> getRecordsNeedRetry();

    /**
     * 清理已过期的同步记录（开始时间在指定天数之前）
     */
    @Query("DELETE FROM calendar_sync_record WHERE startTime < :expireTime")
    int cleanExpiredRecords(long expireTime);

    /**
     * 查询指定时间范围内创建的记录
     */
    @Query("SELECT * FROM calendar_sync_record WHERE createdAt >= :startTime AND createdAt <= :endTime ORDER BY createdAt DESC")
    List<CalendarSyncRecordEntity> getByCreatedTimeRange(long startTime, long endTime);

    /**
     * 更新记录的日历事件详情
     */
    @Query("UPDATE calendar_sync_record SET eventId = :eventId, calendarId = :calendarId, " +
           "syncStatus = 1, syncedAt = :syncedAt WHERE id = :id")
    int updateEventDetails(long id, long eventId, String calendarId, long syncedAt);

    /**
     * 根据来源类型统计记录数
     */
    @Query("SELECT sourceType, COUNT(*) as count FROM calendar_sync_record GROUP BY sourceType")
    List<SourceTypeCount> getCountGroupBySourceType();

    /**
     * 用于统计来源类型的数据类
     */
    class SourceTypeCount {
        public String sourceType;
        public int count;
    }
}

package com.courassistant.java.database;

import android.content.Context;

import androidx.annotation.NonNull;
import androidx.room.Database;
import androidx.room.Room;
import androidx.room.RoomDatabase;
import androidx.room.migration.Migration;
import androidx.sqlite.db.SupportSQLiteDatabase;

/**
 * 法院助手数据库主类
 * 版本1，包含4个表：
 * - court_cases: 案件信息表
 * - court_messages: 短信信息表
 * - court_documents: 文档信息表
 * - calendar_sync_record: 日历同步记录表
 */
@Database(
    entities = {
        CourtCaseEntity.class,
        CourtMessageEntity.class,
        CourtDocumentEntity.class,
        CalendarSyncRecordEntity.class
    },
    version = 1,
    exportSchema = true
)
public abstract class CourtDatabase extends RoomDatabase {

    private static final String DATABASE_NAME = "court_assistant.db";

    private static CourtDatabase instance;

    /**
     * 获取数据库实例（单例模式）
     * @param context 应用上下文
     * @return 数据库实例
     */
    public static synchronized CourtDatabase getInstance(@NonNull Context context) {
        if (instance == null) {
            instance = Room.databaseBuilder(
                    context.getApplicationContext(),
                    CourtDatabase.class,
                    DATABASE_NAME)
                    .addCallback(roomCallback)
                    .allowMainThreadQueries() // 允许主线程查询（仅用于测试，生产环境建议移除）
                    .build();
        }
        return instance;
    }

    /**
     * 获取数据库实例（带迁移支持）
     * @param context 应用上下文
     * @param migrations 数据库迁移列表
     * @return 数据库实例
     */
    public static synchronized CourtDatabase getInstance(@NonNull Context context, Migration... migrations) {
        if (instance == null) {
            Room.Builder<?> builder = Room.databaseBuilder(
                    context.getApplicationContext(),
                    CourtDatabase.class,
                    DATABASE_NAME)
                    .addCallback(roomCallback);

            // 添加迁移
            if (migrations != null && migrations.length > 0) {
                for (Migration migration : migrations) {
                    builder.addMigrations(migration);
                }
            }

            instance = builder.build();
        }
        return instance;
    }

    /**
     * 获取用于测试的内存数据库实例
     * @param context 应用上下文
     * @return 内存数据库实例
     */
    public static synchronized CourtDatabase getInMemoryInstance(@NonNull Context context) {
        return Room.inMemoryDatabaseBuilder(
                context.getApplicationContext(),
                CourtDatabase.class)
                .allowMainThreadQueries()
                .build();
    }

    /**
     * 数据库回调
     */
    private static final RoomDatabase.Callback roomCallback = new RoomDatabase.Callback() {
        @Override
        public void onCreate(@NonNull SupportSQLiteDatabase db) {
            super.onCreate(db);
            // 数据库首次创建时的回调
            // 可以在这里添加初始化数据
        }

        @Override
        public void onOpen(@NonNull SupportSQLiteDatabase db) {
            super.onOpen(db);
            // 数据库打开时的回调
            // 可以在这里添加数据库配置，如启用外键约束
            db.execSQL("PRAGMA foreign_keys=ON");
        }
    };

    /**
     * 获取案件数据访问对象
     */
    public abstract CourtCaseDao courtCaseDao();

    /**
     * 获取短信数据访问对象
     */
    public abstract CourtMessageDao courtMessageDao();

    /**
     * 获取文档数据访问对象
     */
    public abstract CourtDocumentDao courtDocumentDao();

    /**
     * 获取日历同步记录数据访问对象
     */
    public abstract CalendarSyncDao calendarSyncDao();

    /**
     * 清空所有数据（仅用于测试）
     */
    public void clearAllTables() {
        // Room 2.1.0+ 自动实现此方法
        super.clearAllTables();
    }

    /**
     * 关闭数据库实例
     */
    public static void closeInstance() {
        if (instance != null && instance.isOpen()) {
            instance.close();
            instance = null;
        }
    }

    /**
     * 数据库从版本1升级到版本2的迁移示例
     * 当需要升级数据库版本时，添加新的Migration
     */
    public static final Migration MIGRATION_1_2 = new Migration(1, 2) {
        @Override
        public void migrate(@NonNull SupportSQLiteDatabase database) {
            // 示例：添加新列
            // database.execSQL("ALTER TABLE court_cases ADD COLUMN new_column TEXT");
        }
    };

    /**
     * 数据库从版本2升级到版本3的迁移示例
     */
    public static final Migration MIGRATION_2_3 = new Migration(2, 3) {
        @Override
        public void migrate(@NonNull SupportSQLiteDatabase database) {
            // 示例：创建新表
            // database.execSQL("CREATE TABLE IF NOT EXISTS new_table (id INTEGER PRIMARY KEY, data TEXT)");
        }
    };
}
